import { http, HttpResponse, delay } from 'msw'

const TOKEN_KEY = 'tingstudio_token'

export const handlers = [
  http.post('/api/auth/login', async ({ request }) => {
    const body = await request.json() as { username: string; password: string }
    if (body.username === 'admin' && body.password === 'admin123') {
      return HttpResponse.json({
        success: true,
        data: {
          token: 'test-token-mock-xyz',
          user: {
            id: 'u1',
            username: 'admin',
            avatar: '/avatar.jpg',
            role: 'admin'
          }
        }
      })
    }
    return HttpResponse.json(
      { success: false, message: '用户名或密码错误' },
      { status: 401 }
    )
  }),

  http.post('/api/auth/register', async ({ request }) => {
    const body = await request.json() as Record<string, unknown>
    if (!body.username || !body.password) {
      return HttpResponse.json(
        { success: false, message: '请填写完整信息' },
        { status: 400 }
      )
    }
    return HttpResponse.json({
      success: true,
      data: {
        token: 'test-register-token',
        user: { id: 'u-new', username: body.username as string, avatar: '', role: 'user' }
      }
    })
  }),

  http.get('/api/materials', () => {
    return HttpResponse.json({
      success: true,
      data: {
        list: [
          { id: 'm1', name: '当归', category: 'herb', status: 'active', createdAt: '2024-01-15' },
          { id: 'm2', name: '黄芪', category: 'herb', status: 'active', createdAt: '2024-02-10' },
          { id: 'm3', name: '党参', category: 'herb', status: 'inactive', createdAt: '2024-03-05' },
        ],
        total: 3
      }
    })
  }),

  http.get('/api/materials/:id', ({ params }) => {
    const { id } = params
    return HttpResponse.json({
      success: true,
      data: {
        id,
        name: `原料-${id}`,
        category: 'herb',
        nutritionData: { protein: 20.5, fat: 8.3, carbohydrate: 45.2, energy: 1418.2 },
        status: 'active'
      }
    })
  }),

  http.post('/api/materials', async ({ request }) => {
    const body = await request.json()
    return HttpResponse.json({
      success: true,
      data: { id: 'm-new', ...body }
    }, { status: 201 })
  }),

  http.put('/api/materials/:id', async ({ params, request }) => {
    const body = await request.json()
    return HttpResponse.json({
      success: true,
      data: { id: params.id, ...body }
    })
  }),

  http.delete('/api/materials/:id', ({ params }) => {
    return HttpResponse.json({ success: true, data: { id: params.id } })
  }),

  http.get('/api/formulas', () => {
    return HttpResponse.json({
      success: true,
      data: {
        list: [
          { id: 'f1', name: '补气配方-A', code: 'BQ-001', status: 'published', versionCount: 3 },
          { id: 'f2', name: '养血配方-B', code: 'YX-002', status: 'draft', versionCount: 1 },
        ],
        total: 2
      }
    })
  }),

  http.get('/api/formulas/:id', ({ params }) => {
    return HttpResponse.json({
      success: true,
      data: {
        id: params.id,
        name: `配方-${params.id}`,
        code: `CODE-${params.id}`,
        materials: [{ materialId: 'm1', name: '当归', amount: 30 }],
        versions: [
          { id: 'v1', version: '1.0.0', isCurrent: false, createdAt: '2024-01-20' },
          { id: 'v2', version: '1.1.0', isCurrent: true, createdAt: '2024-02-15' },
        ]
      }
    })
  }),

  http.get('/api/salesmen', () => {
    return HttpResponse.json({
      success: true,
      data: {
        list: [
          { id: 's1', name: '张三', phone: '13800138001', region: '华东', status: 'active' },
          { id: 's2', name: '李四', phone: '13800138002', region: '华南', status: 'active' },
        ],
        total: 2
      }
    })
  }),

  http.get('/api/ai/models', () => {
    return HttpResponse.json({
      success: true,
      data: [
        { id: 'gpt-4o', name: 'GPT-4o', provider: 'OpenAI', icon: '🟢' },
        { id: 'claude-sonnet', name: 'Claude Sonnet', provider: 'Anthropic', icon: '🟠' },
        { id: 'deepseek-chat', name: 'DeepSeek Chat', provider: 'DeepSeek', icon: '🔵' },
      ]
    })
  }),

  http.post('/api/ai/chat', async () => {
    await delay(300)
    return HttpResponse.json({
      success: true,
      data: {
        content: '这是 AI 助手的模拟回复。根据您的描述，我建议...',
        model: 'gpt-4o',
        tokensUsed: 156
      }
    })
  }),

  http.get('/api/versions/formula/:formulaId', () => {
    return HttpResponse.json({
      success: true,
      data: {
        list: [
          { id: 'v1', version: '1.0.0', changelog: '初始版本', isCurrent: false, createdAt: '2024-01-20' },
          { id: 'v2', version: '1.1.0', changelog: '调整黄芪用量', isCurrent: true, createdAt: '2024-02-15' },
        ]
      }
    })
  }),

  http.get('/api/exports', () => {
    return HttpResponse.json({
      success: true,
      data: {
        list: [
          { id: 'e1', fileName: '配方导出_202404.xlsx', status: 'completed', progress: 100, createdAt: '2024-04-18' },
          { id: 'e2', fileName: '原料清单.xlsx', status: 'processing', progress: 60, createdAt: '2024-04-19' },
        ]
      }
    })
  }),

  http.get('/api/weather', () => {
    return HttpResponse.json({
      success: true,
      data: {
        city: '北京',
        temperature: 22,
        weather: '晴',
        humidity: 45,
        wind: '东北风 3级'
      }
    })
  }),
]

import { describe, it, expect, vi, beforeEach } from "vitest";

describe("HTTP 客户端工具函数", () => {
  beforeEach(() => {
    localStorage.clear();
  });

  it("H01: getToken 应从 localStorage 获取 token", () => {
    const TOKEN_KEY = "tingstudio_token";
    localStorage.setItem(TOKEN_KEY, "my-token");
    const result = localStorage.getItem(TOKEN_KEY);
    expect(result).toBe("my-token");
  });

  it("H02: setToken 应写入 localStorage", () => {
    const TOKEN_KEY = "tingstudio_token";
    localStorage.setItem(TOKEN_KEY, "new-token");
    expect(localStorage.getItem(TOKEN_KEY)).toBe("new-token");
  });

  it("H03: removeToken 应清除 localStorage", () => {
    const TOKEN_KEY = "tingstudio_token";
    localStorage.setItem(TOKEN_KEY, "exists");
    localStorage.removeItem(TOKEN_KEY);
    expect(localStorage.getItem(TOKEN_KEY)).toBeNull();
  });
});

import http from "./http";

export interface AgentSession {
  id: string;
  user_id: string;
  title: string;
  message_count: number;
  last_intent: string | null;
  last_active_at: string;
  created_at: string;
}

export interface AgentMessage {
  id: string;
  session_id: string;
  role: "user" | "assistant" | "system" | "tool";
  content: string;
  intent: string | null;
  tool_calls: any[] | null;
  tool_results: any[] | null;
  display_type: string | null;
  metadata: any;
  created_at: string;
}

export interface ChatRequest {
  message: string;
  sessionId?: string | null;
  stream?: boolean;
  confirmed?: boolean;
  model?: string;
}

export interface ChatResponse {
  success: boolean;
  type?: string;
  content?: string;
  sessionId?: string;
  usage?: any;
  model?: string;
  toolCalls?: any[];
  toolResults?: any[];
  assistantMessage?: string;
  error?: string;
}

export interface AgentRoleConfig {
  id: string;
  user_id: string;
  agent_name: string;
  user_title: string;
  greeting: string;
  tone_style: string;
  custom_instructions: string;
  updated_at: string;
  created_at: string;
}

export interface AgentFloatConfig {
  id: string;
  userId: string;
  enabled: boolean;
  model: string;
  modelName: string;
  fallbackModel: string;
  fallbackModelName: string;
  position: "right" | "left";
  drawerWidth: number;
  themeColor: string;
  showPulse: boolean;
  enabledPages: string[];
  maxRounds: number;
  fillStrategy: "overwrite" | "preserve";
  contextMode: "page" | "clear";
  updatedAt: string;
  createdAt: string;
}

export interface ParseFormRequest {
  pageId: string;
  utterance: string;
  context?: Array<{ role: "user" | "assistant"; content: string }>;
  sessionId?: string;
}

export interface ParseFormResponse {
  fields: Record<string, any>;
  missingFields: string[];
  message: string;
  sessionId: string;
}

export const agentApi = {
  getSessions() {
    return http.get<any, { success: boolean; data: AgentSession[] }>("/agent/sessions");
  },

  getSessionMessages(sessionId: string) {
    return http.get<any, { success: boolean; data: { id: string; messages: AgentMessage[] } }>(
      `/agent/sessions/${sessionId}`,
    );
  },

  deleteSession(sessionId: string) {
    return http.delete<any, { success: boolean }>(`/agent/sessions/${sessionId}`);
  },

  chat(params: ChatRequest) {
    return http.post<any, ChatResponse>("/agent/chat", {
      message: params.message,
      sessionId: params.sessionId,
      stream: params.stream ?? false,
      confirmed: params.confirmed ?? false,
      model: params.model,
    });
  },

  submitForm(data: { sessionId: string; formId: string; formData: Record<string, any> }) {
    return http.post<
      any,
      {
        success: boolean;
        data?: any;
        error?: string;
        displayType?: string;
        toolName?: string;
        validationErrors?: Array<{ field: string; message: string }>;
      }
    >("/agent/submit-form", data);
  },

  getPendingForm(sessionId: string) {
    return http.get<any, { success: boolean; data: any }>(`/agent/pending-form/${sessionId}`);
  },

  getRoleConfig() {
    return http.get<any, { success: boolean; data: AgentRoleConfig }>("/agent/role-config");
  },

  updateRoleConfig(data: Partial<AgentRoleConfig>) {
    return http.put<any, { success: boolean; data: AgentRoleConfig }>("/agent/role-config", data);
  },

  getFloatConfig() {
    return http.get<any, AgentFloatConfig>("/agent/float-config");
  },

  updateFloatConfig(data: Partial<AgentFloatConfig>) {
    const payload: Record<string, any> = {};
    if (data.enabled !== undefined) payload.enabled = data.enabled;
    if (data.model !== undefined) payload.model = data.model;
    if (data.modelName !== undefined) payload.model_name = data.modelName;
    if (data.fallbackModel !== undefined) payload.fallback_model = data.fallbackModel;
    if (data.fallbackModelName !== undefined) payload.fallback_model_name = data.fallbackModelName;
    if (data.position !== undefined) payload.position = data.position;
    if (data.drawerWidth !== undefined) payload.drawer_width = data.drawerWidth;
    if (data.themeColor !== undefined) payload.theme_color = data.themeColor;
    if (data.showPulse !== undefined) payload.show_pulse = data.showPulse;
    if (data.enabledPages !== undefined) payload.enabled_pages = data.enabledPages;
    if (data.maxRounds !== undefined) payload.max_rounds = data.maxRounds;
    if (data.fillStrategy !== undefined) payload.fill_strategy = data.fillStrategy;
    if (data.contextMode !== undefined) payload.context_mode = data.contextMode;
    return http.put<any, AgentFloatConfig>("/agent/float-config", payload);
  },
  // 解析表单
  parseForm(params: ParseFormRequest) {
    return http.post<any, ParseFormResponse>("/agent/parse-form", params);
  },

  floatChat(params: ParseFormRequest) {
    return http.post<any, any>("/agent/float-chat", params);
  },

  generateDescription(data: {
    formulaName: string;
    materials?: any[];
    finishedWeight?: number;
    revisionReason?: string;
    existingDescription?: string;
    type?: "description" | "preparation" | "version_reason";
  }) {
    return http.post<any, { content: string; type: string }>(
      "/agent/generate-description", data,
    );
  },

  getFieldHints(pageId: string) {
    return http.get<any, { missingFields: string[]; hints: any[]; count: number }>(
      "/agent/field-hints", { params: { pageId } },
    );
  },

  getHealth() {
    return http.get<any, { status: string }>("/agent/health");
  },
};

import http from "./http";

// ─── 类型定义 ───

