// ─── 简单 fetch 封装 ───

async function fetchJSON<T>(url: string): Promise<T> {
  const res = await fetch(url, {
    signal: AbortSignal.timeout(10000),
  })
  if (!res.ok) throw new Error(`HTTP ${res.status}`)
  return res.json()
}

/** 获取环境变量中的高德 Key */
function getAmapKey(): string {
  return import.meta.env.VITE_AMAP_KEY || ''
}

/** 构建代理 URL（开发环境用 Vite 代理，生产环境用后端） */
function proxyUrl(path: string): string {
  const isDev = import.meta.env.DEV
  if (isDev) return `/amap${path}`
  return `/api/weather/amap${path}`
}

// ─── API 方法 ───

/**
 * 城市名搜索 — 高德关键词搜索 / POI 搜索
 * 返回匹配的城市列表
 */
export async function searchCity(keyword: string): Promise<CityLocation[]> {
  try {
    const key = getAmapKey()
    if (!key) return []

    // 使用高德输入提示接口（更精确的中文城市匹配）
    const data = await fetchJSON<{
      status: string
      info: string
      tips?: Array<{
        id: string           // POI ID 或 adcode
        name: string         // 名称
        district: string     // 所属区域
        adcode: string       // 行政区划代码
        location: string     // 经纬度 "lng,lat"
        address: string       // 详细地址
        city: string[]        // 所属城市数组
      }>
    }>(proxyUrl(`/v3/place/text?keywords=${encodeURIComponent(keyword)}&output=json&key=${key}&citylimit=8&extensions=base`))

    if (data.status !== '1' || !data.tips?.length) return []

    return data.tips
      .filter(tip => tip.location && tip.location.split(',').length === 2)
      .map(tip => {
        const [lonStr, latStr] = tip.location.split(',')
        const lat = parseFloat(latStr)
        const lon = parseFloat(lonStr)
        const district = tip.district || ''
        // 从 district 解析省份和城市名
        // district 格式如 "广东省广州市天河区"
        const parts = district.replace(/(省|市|特别行政区|自治区|壮族|回族|维吾尔|藏族)/g, '$1|').split('|').filter(Boolean)

        return {
          name: tip.name,
          id: tip.adcode || `${lat},${lon}`,
          lat,
          lon,
          country: '中国',
          admin1: parts[0] || '',
        }
      })
  } catch (err: any) {
    console.warn('[WeatherAPI] searchCity 失败:', err.message)
    return []
  }
}

/**
 * 获取实时天气 — 高德天气查询 API
 * city 参数支持：城市名称、adcode、经纬度
 */
export async function fetchWeather(locationId: string): Promise<WeatherData | null> {
  try {
    const key = getAmapKey()
    if (!key) throw new Error('未配置高德 Key')

    // 判断 locationId 类型来选择参数格式
    // 如果是经纬度格式（包含逗号和小数点），使用 city 参数传坐标
    let url: string
    const isCoord = /^[+-]?\d+\.?\d*,[+-]?\d+\.?\d*$/.test(locationId)

    if (isCoord) {
      // 经纬度模式
      url = proxyUrl(`/v3/weather/weatherInfo?city=${encodeURIComponent(locationId)}&key=${key}&extensions=base`)
    } else {
      // 城市名/adcode 模式
      url = proxyUrl(`/v3/weather/weatherInfo?city=${encodeURIComponent(locationId)}&key=${key}&extensions=base`)
    }

    const data = await fetchJSON<{
      status: string
      info: string
      infocode: string
      lives?: Array<{
        province: string
        city: string
        adcode: string
        weather: string      // 天气现象文字（如"晴"、"多云"）
        temperature: string   // 温度字符串（如"25"）
        winddirection: string // 风向
        windpower: string     // 风力等级
        humidity: string      // 湿度
        reporttime: string    // 报告时间
      }>
      forecasts?: Array<{
        province: string
        city: string
        adcode: string
        date: string
        daytemp: string
        nighttemp: string
        dayweather: string
        nightweather: string
        daywind: string
        nightwind: string
        daypower: string
        nightpower: string
      }>
    }>(url)

    if (data.status !== '1') throw new Error(data.info || '高德天气API失败')
    if (!data.lives?.length) throw new Error('无天气数据')

    const live = data.lives[0]

    // 根据天气文字反查天气代码（用于图标显示）
    const weatherCode = reverseLookupWeatherCode(live.weather)

    const now: WeatherNow = {
      temp: live.temperature || '--',
      feelsLike: live.temperature || '--',
      icon: String(weatherCode),
      text: live.weather || '--',
      windDir: live.winddirection || '--',
      windScale: live.windpower ? `${live.windpower}级` : '--',
      windSpeed: windPowerToSpeed(live.windpower),
      humidity: live.humidity || '--',
      precip: '--',
      pressure: '--',
      vis: '--',
    }

    // 解析位置信息
    const locName = live.city || live.province || ''
    let lat = 0, lon = 0

    // 如果是经纬度 ID，尝试保留坐标
    if (isCoord) {
      const [lonStr, latStr] = locationId.split(',')
      lat = parseFloat(latStr)
      lon = parseFloat(lonStr)
      if (isNaN(lat)) lat = 0
      if (isNaN(lon)) lon = 0
    }

    return {
      location: {
        name: locName,
        id: locationId,
        lat,
        lon,
        country: '中国',
        admin1: live.province || '',
      },
      now,
      updateTime: live.reporttime || new Date().toISOString(),
    }
  } catch (err: any) {
    console.warn('[WeatherAPI] fetchWeather 失败:', err.message)
    return null
  }
}

/**
 * 逆地理编码 — 经纬度 → 城市信息（高德 /v3/geocode/regeo）
 * 返回城市的 adcode 和名称
 */
export async function reverseGeocode(lat: number, lon: number): Promise<{ adcode: string; name: string } | null> {
  try {
    const key = getAmapKey()
    if (!key) return null

    const data = await fetchJSON<{
      status: string
      info: string
      regeocode?: {
        addressComponent?: {
          city: string[]
          province: string
          district: string[]
          adcode: string
        }
      }
    }>(proxyUrl(`/v3/geocode/regeo?location=${lon},${lat}&key=${key}&extensions=base&output=json`))

    if (data.status !== '1' || !data.regeocode?.addressComponent) return null

    const comp = data.regeocode.addressComponent
    // 高德返回的 city 可能是空数组（直辖市），用 province 或 district 兜底
    const rawCity = Array.isArray(comp.city) ? comp.city[0] : ''
    const rawDistrict = Array.isArray(comp.district) ? comp.district[0] : ''
    const name = rawCity || rawDistrict || comp.province || '未知'
    const adcode = comp.adcode

    console.log('[WeatherAPI] 逆地理编码:', lon, lat, '→', name, '(' + adcode + ')')
    return { adcode, name }
  } catch (err: any) {
    console.warn('[WeatherAPI] reverseGeocode 失败:', err.message)
    return null
  }
}

/**
 * 通过天气文字反查高德天气现象代码
 */
function reverseLookupWeatherCode(weatherText: string): number {
  const map: Record<string, number> = {
    '晴': 0,
    '多云': 1,
    '少云': 2,
    '晴间多云': 3,
    '阴': 4,
    '阵雨': 5,
    '阵雪': 6,
    '雨夹雪': 7,
    '毛毛雨': 8, '细雨': 8, '小雨': 9,
    '中雨': 10,
    '大雨': 11,
    '暴雨': 12,
    '大暴雨': 13, '特大暴雨': 13,
    '小雪': 14,
    '中雪': 15,
    '大雪': 16,
    '暴雪': 17,
    '雾': 18,
    '冻雨': 19,
    '沙尘暴': 20, '沙尘': 21, '扬沙': 22, '浮尘': 23,
    '霾': 49,
    '未知': 99,
  }
  return map[weatherText] ?? 1
}

/**
 * 风力等级（如"≤3"或"4-5"）→ 近似风速 km/h
 */
function windPowerToSpeed(power: string | undefined): string {
  if (!power) return '--'
  // 提取数字（处理 "≤3", "4-5", "3" 等格式）
  const match = power.match(/\d+/)
  if (!match) return '--'
  const level = parseInt(match[0], 10)
  // 蒲福风级近似换算（km/h）
  const speeds: Record<number, number> = {
    0: 1, 1: 5, 2: 11, 3: 19, 4: 28,
    5: 38, 6: 50, 7: 62, 8: 74, 9: 88,
    10: 102, 11: 117, 12: 133,
  }
  return String(speeds[level] ?? level * 12)
}

export interface FillResult {
  key: string;
  value: any;
  success: boolean;
  error?: string;
}

function findInput(key: string): HTMLElement | null {
  const selectors = [
    `[data-field="${key}"]`,
    `input[name="${key}"]`,
    `textarea[name="${key}"]`,
    `select[name="${key}"]`,
    `[data-testid="${key}"]`,
    `#${key}`,
  ];
  for (const sel of selectors) {
    const el = document.querySelector<HTMLElement>(sel);
    if (el) return el;
  }
  return null;
}

function setNativeValue(el: HTMLInputElement | HTMLTextAreaElement, value: string) {
  const valueSetter = Object.getOwnPropertyDescriptor(HTMLInputElement.prototype, "value")?.set
    || Object.getOwnPropertyDescriptor(HTMLTextAreaElement.prototype, "value")?.set;
  if (valueSetter) {
    valueSetter.call(el, value);
  } else {
    el.value = value;
  }
  el.dispatchEvent(new Event("input", { bubbles: true }));
  el.dispatchEvent(new Event("change", { bubbles: true }));
}

function fillTDesignInput(container: HTMLElement, value: any): FillResult | null {
  const innerInput = container.querySelector<HTMLInputElement>("input.t-input__inner");
  if (innerInput) {
    setNativeValue(innerInput, String(value));
    return null;
  }
  return null;
}

function fillTDesignTextarea(container: HTMLElement, value: any): FillResult | null {
  const innerTextarea = container.querySelector<HTMLTextAreaElement>("textarea.t-textarea__inner");
  if (innerTextarea) {
    setNativeValue(innerTextarea, String(value));
    return null;
  }
  return null;
}

function fillTDesignInputNumber(container: HTMLElement, value: any): FillResult | null {
  const innerInput = container.querySelector<HTMLInputElement>("input.t-input-number__input");
  if (!innerInput) {
    const fallbackInput = container.querySelector<HTMLInputElement>("input.t-input__inner");
    if (fallbackInput) {
      setNativeValue(fallbackInput, String(value));
      return null;
    }
    return null;
  }
  setNativeValue(innerInput, String(value));
  return null;
}

interface PartialFillResult {
  value: any;
  success: boolean;
  error?: string;
}

function fillTDesignSelect(container: HTMLElement, value: any): PartialFillResult {
  const options = container.querySelectorAll<HTMLElement>(".t-select-option, .t-select__option");
  for (const opt of options) {
    const optText = opt.textContent?.trim();
    const optValue = opt.getAttribute("data-value") || opt.getAttribute("value");
    if (optText === String(value) || optValue === String(value)) {
      opt.click();
      return { value, success: true };
    }
  }

  const input = container.querySelector<HTMLInputElement>("input.t-input__inner");
  if (input) {
    input.focus();
    setNativeValue(input, String(value));
    return { value, success: true };
  }

  return { value, success: false, error: "下拉选项未匹配" };
}

function fillTDesignRadioGroup(container: HTMLElement, value: any): PartialFillResult {
  const radios = container.querySelectorAll<HTMLInputElement>("input[type=\"radio\"]");
  for (const radio of radios) {
    if (radio.value === String(value)) {
      radio.checked = true;
      radio.dispatchEvent(new Event("change", { bubbles: true }));
      const label = radio.closest<HTMLElement>("label") || radio.parentElement;
      if (label) label.click();
      return { value, success: true };
    }
  }

  const labels = container.querySelectorAll<HTMLElement>(".t-radio, .t-radio-button");
  for (const label of labels) {
    const labelText = label.textContent?.trim();
    if (labelText === String(value)) {
      label.click();
      return { value, success: true };
    }
  }

  const valueMap: Record<string, string> = {
    "药材": "herb",
    "辅料": "supplement",
    "是": "true",
    "否": "false",
  };
  const mappedValue = valueMap[String(value)];
  if (mappedValue) {
    for (const radio of radios) {
      if (radio.value === mappedValue) {
        radio.checked = true;
        radio.dispatchEvent(new Event("change", { bubbles: true }));
        const label = radio.closest<HTMLElement>("label") || radio.parentElement;
        if (label) label.click();
        return { value, success: true };
      }
    }
  }

  return { value, success: false, error: "单选值未匹配" };
}

function fillSingleField(key: string, value: any): FillResult {
  const el = findInput(key);
  if (!el) {
    return { key, value, success: false, error: "未找到对应输入框" };
  }

  const isTDesignSelect = el.classList.contains("t-select") || el.classList.contains("t-select__wrap")
    || el.querySelector(".t-select") !== null;
  const isTDesignRadioGroup = el.classList.contains("t-radio-group")
    || el.querySelector(".t-radio-group") !== null;
  const isTDesignInputNumber = el.classList.contains("t-input-number")
    || el.querySelector(".t-input-number") !== null;
  const isTDesignInput = el.classList.contains("t-input") || el.querySelector("input.t-input__inner") !== null;
  const isTDesignTextarea = el.classList.contains("t-textarea") || el.querySelector("textarea.t-textarea__inner") !== null;

  if (isTDesignSelect) {
    const selectEl = el.classList.contains("t-select") ? el : el.querySelector<HTMLElement>(".t-select") || el;
    const result = fillTDesignSelect(selectEl, value);
    return { key, ...result };
  }

  if (isTDesignRadioGroup) {
    const radioEl = el.classList.contains("t-radio-group") ? el : el.querySelector<HTMLElement>(".t-radio-group") || el;
    const result = fillTDesignRadioGroup(radioEl, value);
    return { key, ...result };
  }

  if (isTDesignInputNumber) {
    const numEl = el.classList.contains("t-input-number") ? el : el.querySelector<HTMLElement>(".t-input-number") || el;
    fillTDesignInputNumber(numEl, value);
    return { key, value, success: true };
  }

  if (isTDesignTextarea) {
    const taEl = el.classList.contains("t-textarea") ? el : el.querySelector<HTMLElement>(".t-textarea") || el;
    fillTDesignTextarea(taEl, value);
    return { key, value, success: true };
  }

  if (isTDesignInput) {
    const inputEl = el.classList.contains("t-input") ? el : el.querySelector<HTMLElement>(".t-input") || el;
    fillTDesignInput(inputEl, value);
    return { key, value, success: true };
  }

  const tag = el.tagName.toLowerCase();

  if (tag === "select") {
    const select = el as HTMLSelectElement;
    const option = Array.from(select.options).find(
      o => o.value === String(value) || o.textContent?.trim() === String(value),
    );
    if (option) {
      select.value = option.value;
      select.dispatchEvent(new Event("change", { bubbles: true }));
      return { key, value, success: true };
    }
    return { key, value, success: false, error: "下拉选项未匹配" };
  }

  if (tag === "input") {
    const input = el as HTMLInputElement;
    const type = input.type?.toLowerCase();

    if (type === "checkbox") {
      input.checked = !!value;
      input.dispatchEvent(new Event("change", { bubbles: true }));
      return { key, value, success: true };
    }

    if (type === "radio") {
      const radio = document.querySelector<HTMLInputElement>(
        `input[type="radio"][name="${key}"][value="${value}"]`,
      );
      if (radio) {
        radio.checked = true;
        radio.dispatchEvent(new Event("change", { bubbles: true }));
        return { key, value, success: true };
      }
      return { key, value, success: false, error: "单选值未匹配" };
    }

    setNativeValue(input, String(value));
    return { key, value, success: true };
  }

  if (tag === "textarea") {
    setNativeValue(el as HTMLTextAreaElement, String(value));
    return { key, value, success: true };
  }

  const innerInput = el.querySelector<HTMLInputElement | HTMLTextAreaElement>("input, textarea, select");
  if (innerInput) {
    if (innerInput.tagName.toLowerCase() === "select") {
      return fillSingleField(key, value);
    }
    setNativeValue(innerInput as HTMLInputElement, String(value));
    return { key, value, success: true };
  }

  return { key, value, success: false, error: "不支持的元素类型" };
}

export function fillFormFields(fields: Record<string, any>): FillResult[] {
  const results: FillResult[] = [];

  for (const [key, value] of Object.entries(fields)) {
    if (value === undefined || value === null) continue;

    if (key === "materials" && typeof value === "string") {
      const parts = value.split(",").map(s => s.trim()).filter(Boolean);
      let filled = false;
      for (const part of parts) {
        const [matName, amount] = part.split(":").map(s => s.trim());
        if (matName) {
          const r = fillSingleField("material_name", matName);
          if (r.success) filled = true;
        }
        if (amount) {
          const r = fillSingleField("material_amount", amount);
          if (r.success) filled = true;
        }
      }
      results.push({ key, value, success: filled });
      continue;
    }

    results.push(fillSingleField(key, value));
  }

  return results;
}

