  const apiInterfaces = ref<ApiInterface[]>([])
  const loading = ref(false)
  const total = ref(0)
  const currentPage = ref(1)
  const pageSize = ref(10)
  const templateTotal = ref(0)
  const templateCurrentPage = ref(1)
  const templatePageSize = ref(10)
  const apiTotal = ref(0)
  const apiCurrentPage = ref(1)
  const apiPageSize = ref(10)

  // ===== 模板 =====
  const fetchTemplates = async (params?: { type?: string; page?: number; pageSize?: number }) => {
    loading.value = true
    try {
      const res = await exportApi.getTemplates(params)
      templates.value = res.list
      templateTotal.value = res.pagination.total
      templateCurrentPage.value = res.pagination.page
      templatePageSize.value = res.pagination.pageSize
    } catch (error) {
      console.error('获取导出模板失败:', error)
    } finally {
      loading.value = false
    }
  }

  const createTemplate = async (data: { name: string; description?: string; type: string; formatConfig: any; isDefault?: boolean }) => {
    try {
      await exportApi.createTemplate(data)
      await fetchTemplates({ page: templateCurrentPage.value, pageSize: templatePageSize.value })
      return { success: true }
    } catch (error: any) {
      return { success: false, message: error.message || '创建模板失败' }
    }
  }

  const updateTemplate = async (templateId: string, data: { name: string; description?: string; type: string; formatConfig: any; isDefault?: boolean }) => {
    try {
      await exportApi.updateTemplate(templateId, data)
      await fetchTemplates({ page: templateCurrentPage.value, pageSize: templatePageSize.value })
      return { success: true }
    } catch (error: any) {
      return { success: false, message: error.message || '更新模板失败' }
    }
  }

  const deleteTemplate = async (templateId: string) => {
    try {
      await exportApi.deleteTemplate(templateId)
      await fetchTemplates({ page: templateCurrentPage.value, pageSize: templatePageSize.value })
      return { success: true }
    } catch (error: any) {
      return { success: false, message: error.message || '删除模板失败' }
    }
  }

  // ===== 导出任务 =====
  const createJob = async (data: { formulaId: string; versionId?: string; templateId?: string; exportType: string }) => {
    loading.value = true
    try {
      const res = await exportApi.createJob(data)
      return { success: true, data: res }
    } catch (error: any) {
      return { success: false, message: error.message || '创建导出任务失败' }
    } finally {
      loading.value = false
    }
  }

  const fetchJobs = async (params?: { status?: string; page?: number; pageSize?: number }) => {
    loading.value = true
    try {
      const res = await exportApi.getJobs(params)
      // axios 拦截器已经提取了 res.data，所以这里直接使用 res
      jobs.value = res.list
      total.value = res.pagination.total
    } catch (error) {
      console.error('获取导出任务失败:', error)
    } finally {
      loading.value = false
    }
  }

  const getJob = async (jobId: string): Promise<ExportJob | null> => {
    try {
      const res = await exportApi.getJob(jobId)
      // axios 拦截器已经提取了 res.data，所以这里直接使用 res
      return res
    } catch {
      return null
    }
  }

  const retryJob = async (jobId: string) => {
    try {
      await exportApi.retryJob(jobId)
      await fetchJobs({ page: currentPage.value, pageSize: pageSize.value })
      return { success: true }
    } catch (error: any) {
      return { success: false, message: error.message || '重试失败' }
    }
  }

  const reExportJob = async (jobId: string) => {
    try {
      await exportApi.reExportJob(jobId)
      await fetchJobs({ page: currentPage.value, pageSize: pageSize.value })
      return { success: true }
    } catch (error: any) {
      return { success: false, message: error.message || '重新导出失败' }
    }
  }

  const downloadFile = async (jobId: string, fileName: string, exportType: string = 'excel') => {
    try {
      const res = await exportApi.downloadFile(jobId)
      const contentType = exportType === 'pdf'
        ? 'application/pdf'
        : 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
      const blob = new Blob([res.data], { type: contentType })
      const url = window.URL.createObjectURL(blob)
      const link = document.createElement('a')
      link.href = url
      link.download = fileName
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
      window.URL.revokeObjectURL(url)
      return { success: true }
    } catch (error: any) {
      return { success: false, message: error.message || '下载失败' }
    }
  }

  // ===== 分享 =====
  const createShare = async (data: { formulaId: string; versionId?: string; shareType?: string; password?: string; expireDate?: string; downloadLimit?: number }) => {
    try {
      const res = await exportApi.createShare(data)
      return { success: true, data: res }
    } catch (error: any) {
      return { success: false, message: error.message || '创建分享失败' }
    }
  }
  
  const fetchShares = async () => {
    try {
      const res = await exportApi.getShares()
      // axios 拦截器已经提取了 res.data，所以这里直接使用 res
      shares.value = res
    } catch (error) {
      console.error('获取分享列表失败:', error)
    }
  }
  
  const deleteShare = async (shareId: string) => {
    try {
      await exportApi.deleteShare(shareId)
      await fetchShares()
      return { success: true }
    } catch (error: any) {
      return { success: false, message: error.message || '删除分享失败' }
    }
  }
  
  // ===== API 接口 =====
  const fetchApiInterfaces = async (params?: { page?: number; pageSize?: number }) => {
    try {
      const res = await exportApi.getApiInterfaces(params)
      apiInterfaces.value = res.list
      apiTotal.value = res.pagination.total
      apiCurrentPage.value = res.pagination.page
      apiPageSize.value = res.pagination.pageSize
    } catch (error) {
      console.error('获取 API 接口列表失败:', error)
    }
  }
  
  const createApiInterface = async (data: any) => {
    try {
      await exportApi.createApiInterface(data)
      await fetchApiInterfaces({ page: apiCurrentPage.value, pageSize: apiPageSize.value })
      return { success: true }
    } catch (error: any) {
      return { success: false, message: error.message || '创建 API 接口失败' }
    }
  }

  // ===== 分页 =====
  const setPage = (page: number) => {
    currentPage.value = page
  }
  const setTemplatePage = (page: number) => {
    templateCurrentPage.value = page
  }
  const setApiPage = (page: number) => {
    apiCurrentPage.value = page
  }

  return {
    templates, jobs, shares, apiInterfaces,
    loading, total, currentPage, pageSize,
    templateTotal, templateCurrentPage, templatePageSize,
    apiTotal, apiCurrentPage, apiPageSize,
    fetchTemplates, createTemplate, updateTemplate, deleteTemplate,
    createJob, fetchJobs, getJob, retryJob, reExportJob, downloadFile,
    createShare, fetchShares, deleteShare,
    fetchApiInterfaces, createApiInterface,
    setPage, setTemplatePage, setApiPage,
  }
})

import { defineStore } from 'pinia'
import { ref } from 'vue'
import { fileApi } from '@/api/file'
import type { UploadedFile, FileQueryParams, FileStats, AuditLog, FilePreviewData } from '@/api/file'
import { MessagePlugin } from 'tdesign-vue-next'

export const useFileStore = defineStore('file', () => {
  const files = ref<UploadedFile[]>([])
  const total = ref(0)
  const loading = ref(false)
  const stats = ref<FileStats>({ total: 0, parsed: 0, linked: 0, pending: 0, totalSize: 0 })
  const currentFile = ref<UploadedFile | null>(null)
  const auditLogs = ref<AuditLog[]>([])
  const previewData = ref<FilePreviewData | null>(null)
  const previewLoading = ref(false)

  const queryParams = ref<FileQueryParams>({
    keyword: '',
    fileType: undefined,
    relatedStatus: undefined,
    startDate: undefined,
    endDate: undefined,
    page: 1,
    pageSize: 8,
  })

  async function fetchFiles(params?: FileQueryParams) {
    loading.value = true
    try {
      const merged = { ...queryParams.value, ...params }
      queryParams.value = merged
      const res = await fileApi.list(merged)
      files.value = res.list
      total.value = res.total
      if (res.stats) stats.value = res.stats
    } catch (error) {
      console.error('获取文件列表失败:', error)
    } finally {
      loading.value = false
    }
  }

  async function uploadFile(file: File, fileType: string) {
    loading.value = true
    try {
      const formData = new FormData()
      formData.append('file', file)
      formData.append('fileType', fileType)
      const res = await fileApi.upload(formData)
      MessagePlugin.success('文件上传成功')
      await fetchFiles()
      return { success: true, data: res }
    } catch (error: any) {
      MessagePlugin.error(error.message || '文件上传失败')
      return { success: false, message: error.message }
    } finally {
      loading.value = false
    }
  }

  async function getFile(fileId: string) {
    loading.value = true
    try {
      const res = await fileApi.get(fileId)
      currentFile.value = res
      return res
    } catch (error: any) {
      MessagePlugin.error('获取文件详情失败')
      return null
    } finally {
      loading.value = false
    }
  }

  async function deleteFile(fileId: string) {
    try {
      await fileApi.delete(fileId)
      MessagePlugin.success('文件已删除')
      await fetchFiles()
      return { success: true }
    } catch (error: any) {
      MessagePlugin.error(error.message || '删除失败')
      return { success: false, message: error.message }
    }
  }

  async function batchDelete(fileIds: string[]) {
    try {
      const res = await fileApi.batchDelete(fileIds)
      MessagePlugin.success(`已删除 ${res.deleted} 个文件`)
      await fetchFiles()
      return { success: true, data: res }
    } catch (error: any) {
      MessagePlugin.error(error.message || '批量删除失败')
      return { success: false, message: error.message }
    }
  }

  async function batchArchive(fileIds: string[]) {
    try {
      const res = await fileApi.batchArchive(fileIds)
      MessagePlugin.success(`已归档 ${res.archived} 个文件`)
      await fetchFiles()
      return { success: true, data: res }
    } catch (error: any) {
      MessagePlugin.error(error.message || '批量归档失败')
      return { success: false, message: error.message }
    }
  }

  async function linkFile(fileId: string, relatedId: string, relatedType: string) {
    try {
      await fileApi.link(fileId, { relatedId, relatedType })
      MessagePlugin.success('关联成功')
      if (currentFile.value && currentFile.value.fileId === fileId) {
        await getFile(fileId)
      }
      return { success: true }
    } catch (error: any) {
      MessagePlugin.error(error.message || '关联失败')
      return { success: false, message: error.message }
    }
  }

  async function unlinkFile(fileId: string, relatedId?: string, relatedType?: string) {
    try {
      await fileApi.unlink(fileId, relatedId && relatedType ? { relatedId, relatedType } : undefined)
      MessagePlugin.success('已解除关联')
      if (currentFile.value && currentFile.value.fileId === fileId) {
        await getFile(fileId)
      }
      return { success: true }
    } catch (error: any) {
      MessagePlugin.error(error.message || '解除关联失败')
      return { success: false, message: error.message }
    }
  }

  async function reparseFile(fileId: string, model: string) {
    try {
      await fileApi.reparse(fileId, model)
      MessagePlugin.success('重新解析已启动')
      if (currentFile.value && currentFile.value.fileId === fileId) {
        await getFile(fileId)
      }
      return { success: true }
    } catch (error: any) {
      MessagePlugin.error(error.message || '重新解析失败')
      return { success: false, message: error.message }
    }
  }

  async function fetchAuditLog(fileId: string) {
    try {
      const res = await fileApi.getAuditLog(fileId)
      auditLogs.value = res
      return res
    } catch (error) {
      console.error('获取审计日志失败:', error)
      return []
    }
  }

  async function fetchPreview(fileId: string, params?: { sheet?: number; maxRows?: number; maxCols?: number }) {
    previewLoading.value = true
    try {
      const res = await fileApi.preview(fileId, params)
      previewData.value = res
      return res
    } catch (error: any) {
      console.error('获取预览数据失败:', error)
      previewData.value = null
      return null
    } finally {
      previewLoading.value = false
    }
  }

  async function downloadFile(fileId: string, fileName: string) {
    try {
      const res = await fileApi.download(fileId)
      const blob = new Blob([res.data])
      const url = window.URL.createObjectURL(blob)
      const link = document.createElement('a')
      link.href = url
      link.download = fileName
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
      window.URL.revokeObjectURL(url)
      return { success: true }
    } catch (error: any) {
      MessagePlugin.error(error.message || '下载失败')
      return { success: false, message: error.message }
    }
  }

  async function fetchStats() {
    try {
      const res = await fileApi.getStats()
      stats.value = res
      return res
    } catch (error) {
      console.error('获取文件统计失败:', error)
      return null
    }
  }

  function setPage(page: number) {
    queryParams.value.page = page
  }

  function resetQuery() {
    queryParams.value = {
      keyword: '',
      fileType: undefined,
      relatedStatus: undefined,
      startDate: undefined,
      endDate: undefined,
      page: 1,
      pageSize: 8,
    }
  }

  return {
    files, total, loading, stats, currentFile, auditLogs,
    previewData, previewLoading, queryParams,
    fetchFiles, uploadFile, getFile, deleteFile,
    batchDelete, batchArchive,
    linkFile, unlinkFile, reparseFile,
    fetchAuditLog, fetchPreview, downloadFile, fetchStats,
    setPage, resetQuery,
  }
})

import { defineStore } from "pinia";
import { ref, computed } from "vue";
import { agentApi, type AgentFloatConfig, type ParseFormRequest } from "@/api/agent";

export interface FloatMessage {
  id: string;
  role: "user" | "assistant";
  content: string;
  fields?: Record<string, any>;
  missingFields?: string[];
  toolName?: string;
  displayType?: string;
  toolData?: any;
  metadata?: { model?: string; latency?: number; tokenUsage?: any };
  timestamp: number;
}

const DEFAULT_CONFIG: AgentFloatConfig = {
  id: "",
  userId: "",
  enabled: true,
  model: "deepseek",
  modelName: "",
  fallbackModel: "",
  fallbackModelName: "",
  position: "right",
  drawerWidth: 400,
  themeColor: "",
  showPulse: true,
  enabledPages: [],
  maxRounds: 10,
  fillStrategy: "overwrite",
  contextMode: "page",
  updatedAt: "",
  createdAt: "",
};

const FORM_PAGE_IDS = ["formula-add", "formula-edit", "material-add", "material-edit", "salesman-add", "salesman-edit"];

const API_BASE = import.meta.env?.VITE_API_BASE_URL || "/api";

function classifyFloatIntent(utterance: string): "fill" | "agent" {
  const text = utterance.toLowerCase();
  if (/对比|比较|vs|区别|差异/.test(text)) return "agent";
  if (/替代|替换|代替|换掉|替补/.test(text)) return "agent";
  if (/报价|报价单|多少钱|售价|定价|价格/.test(text)) return "agent";
  if (/生成描述|生成制法|智能生成|写描述|写制法|帮我写/.test(text)) return "agent";
  if (/算|计算|校验|合规|营养|成本|含量比|系数/.test(text)) return "agent";
  if (/什么意思|合规吗|范围|规范|单位|标准|规则|是什么|怎么填|能不能|可以吗/.test(text)) return "agent";
  return "fill";
}

export const useFloatAgentStore = defineStore("floatAgent", () => {
  const isOpen = ref(false);
  const isFullscreen = ref(false);
  const loading = ref(false);
  const messages = ref<FloatMessage[]>([]);
  const currentPageId = ref<string>("");
  const sessionId = ref<string | null>(null);
  const config = ref<AgentFloatConfig>({ ...DEFAULT_CONFIG });
  const configLoaded = ref(false);
  const fieldHintsCount = ref(0);
  const missingFieldsList = ref<string[]>([]);
  const agentHealthStatus = ref<"online" | "loading" | "error">("online");

  const isVisible = computed(() => {
    if (!config.value.enabled) return false;
    if (config.value.enabledPages.length === 0) return FORM_PAGE_IDS.includes(currentPageId.value);
    return config.value.enabledPages.includes(currentPageId.value);
  });

  const badgeCount = computed(() => fieldHintsCount.value);

  const dynamicTitle = computed(() => {
    const titleMap: Record<string, string> = {
      "formula-add": "新增配方",
      "formula-edit": "编辑配方",
      "material-add": "新增原料",
      "material-edit": "编辑原料",
      "salesman-add": "新增业务员",
      "salesman-edit": "编辑业务员",
    };
    return titleMap[currentPageId.value] || "AI 助手";
  });

  async function loadConfig() {
    try {
      const data = await agentApi.getFloatConfig();
      if (data) {
        config.value = data;
      }
      configLoaded.value = true;
    } catch (error) {
      console.error("[FloatAgent] 加载配置失败:", error);
      configLoaded.value = true;
    }
  }

  async function saveConfig(partial: Partial<AgentFloatConfig>) {
    try {
      const data = await agentApi.updateFloatConfig(partial);
      if (data) {
        config.value = data;
      }
      return true;
    } catch (error) {
      console.error("[FloatAgent] 保存配置失败:", error);
      return false;
    }
  }

  function setPageId(pageId: string) {
    if (currentPageId.value !== pageId) {
      currentPageId.value = pageId;
      if (config.value.contextMode === "page") {
        messages.value = [];
        sessionId.value = null;
      }
    }
  }

  function toggleOpen() {
    isOpen.value = !isOpen.value;
  }

  function setOpen(val: boolean) {
    isOpen.value = val;
  }

  function toggleFullscreen() {
    isFullscreen.value = !isFullscreen.value;
  }

  function clearMessages() {
    messages.value = [];
    sessionId.value = null;
  }

  async function fetchFieldHints() {
    if (!currentPageId.value) return;
    try {
      const data = await agentApi.getFieldHints(currentPageId.value);
      if (data && typeof data.count === "number") {
        missingFieldsList.value = data.missingFields || [];
      }
    } catch {
      missingFieldsList.value = [];
    }
  }

  function updateFieldHintsLocal(missingFields: string[], count: number) {
    missingFieldsList.value = missingFields;
    fieldHintsCount.value = count;
  }

  function showMissingFieldsHint() {
    if (missingFieldsList.value.length === 0 || messages.value.length > 0) return;
    const aiMsg: FloatMessage = {
      id: `msg_${Date.now()}_ai`,
      role: "assistant",
      content: "检测到表单存在未填写的必填字段，请提供以下信息：",
      missingFields: missingFieldsList.value,
      timestamp: Date.now(),
    };
    messages.value.push(aiMsg);
  }

  async function fetchHealth() {
    try {
      const data = await agentApi.getHealth();
      if (data && data.status) {
        agentHealthStatus.value = data.status as any;
      }
    } catch {
      agentHealthStatus.value = "error";
    }
  }

  async function sendMessage(utterance: string) {
    if (!utterance.trim() || !currentPageId.value) return;

    const userMsg: FloatMessage = {
      id: `msg_${Date.now()}_user`,
      role: "user",
      content: utterance,
      timestamp: Date.now(),
    };
    messages.value.push(userMsg);

    const intent = classifyFloatIntent(utterance);

    if (intent === "fill") {
      await sendFillMessage(utterance);
    } else {
      await sendAgentMessage(utterance);
    }
  }

  async function sendFillMessage(utterance: string) {
    loading.value = true;
    try {
      const context = messages.value
        .slice(-6)
        .filter(m => m.role === "user" || m.role === "assistant")
        .map(m => ({ role: m.role, content: m.content }));

      const params: ParseFormRequest = {
        pageId: currentPageId.value,
        utterance,
        context,
        sessionId: sessionId.value || undefined,
      };
      const data = await agentApi.parseForm(params);

      if (data && (data.fields || data.missingFields)) {
        sessionId.value = data.sessionId;
        const fieldCount = data.fields ? Object.keys(data.fields).length : 0;
        const aiMsg: FloatMessage = {
          id: `msg_${Date.now()}_ai`,
          role: "assistant",
          content: data.message || (fieldCount > 0 ? `已解析${fieldCount}个字段` : "请提供更多信息"),
          fields: data.fields || {},
          missingFields: data.missingFields || [],
          timestamp: Date.now(),
        };
        messages.value.push(aiMsg);
      } else {
        const aiMsg: FloatMessage = {
          id: `msg_${Date.now()}_ai`,
          role: "assistant",
          content: (data as any)?.message || "解析失败，请重新描述",
          timestamp: Date.now(),
        };
        messages.value.push(aiMsg);
      }
    } catch (error: any) {
      const aiMsg: FloatMessage = {
        id: `msg_${Date.now()}_ai`,
        role: "assistant",
        content: error?.message || "网络异常，请稍后重试",
        timestamp: Date.now(),
      };
      messages.value.push(aiMsg);
    } finally {
      loading.value = false;
    }
  }

  async function sendAgentMessage(utterance: string) {
    loading.value = true;

    const aiMsgId = `msg_${Date.now()}_ai`;
    const aiMsg: FloatMessage = {
      id: aiMsgId,
      role: "assistant",
      content: "",
      timestamp: Date.now(),
    };
    messages.value.push(aiMsg);

    try {
      const context = messages.value
        .slice(-6)
        .filter(m => m.role === "user" || m.role === "assistant" && m.id !== aiMsgId)
        .map(m => ({ role: m.role, content: m.content }));

      const token = localStorage.getItem("tingstudio_token");
      const resp = await fetch(`${API_BASE}/agent/float-chat`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          ...(token ? { Authorization: `Bearer ${token}` } : {}),
        },
        body: JSON.stringify({
          pageId: currentPageId.value,
          utterance,
          context,
          sessionId: sessionId.value || undefined,
        }),
      });

      if (!resp.ok) {
        const err = await resp.json().catch(() => ({}));
        updateMessage(aiMsgId, { content: err.error || "请求失败" });
        return;
      }

      const reader = resp.body?.getReader();
      if (!reader) {
        updateMessage(aiMsgId, { content: "无法读取响应流" });
        return;
      }

      const decoder = new TextDecoder();
      let buffer = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split("\n");
        buffer = lines.pop() || "";

        for (const line of lines) {
          if (!line.startsWith("data: ")) continue;
          const jsonStr = line.slice(6).trim();
          if (!jsonStr || jsonStr === "[DONE]") continue;

          try {
            const evt = JSON.parse(jsonStr);
            handleSSEEvent(evt, aiMsgId);
          } catch {
            // ignore parse error for SSE chunk
          }
        }
      }
    } catch (error) {
      updateMessage(aiMsgId, { content: "网络异常，请稍后重试" });
    } finally {
      loading.value = false;
    }
  }

  function handleSSEEvent(evt: any, aiMsgId: string) {
    switch (evt.type) {
      case "chunk":
        appendMessageContent(aiMsgId, evt.content || "");
        break;
      case "content_clear":
        updateMessage(aiMsgId, { content: "" });
        break;
      case "tool_calls":
        break;
      case "tool_result":
        updateMessage(aiMsgId, {
          toolName: evt.toolName,
          displayType: evt.displayType,
          toolData: evt.data,
        });
        break;
      case "write_guidance":
        updateMessage(aiMsgId, {
          content: evt.message || "此操作需要前往对应页面完成",
          toolName: evt.toolName,
        });
        break;
      case "done":
        if (evt.sessionId) sessionId.value = evt.sessionId;
        updateMessage(aiMsgId, {
          displayType: evt.displayType || undefined,
          metadata: {
            model: evt.model,
            latency: evt.latency,
            tokenUsage: evt.usage,
          },
        });
        break;
      case "error":
        updateMessage(aiMsgId, { content: evt.message || "发生错误" });
        break;
    }
  }

  function updateMessage(id: string, patch: Partial<FloatMessage>) {
    const idx = messages.value.findIndex(m => m.id === id);
    if (idx >= 0) {
      messages.value[idx] = { ...messages.value[idx], ...patch };
    }
  }

  function appendMessageContent(id: string, chunk: string) {
    const idx = messages.value.findIndex(m => m.id === id);
    if (idx >= 0) {
      messages.value[idx] = { ...messages.value[idx], content: (messages.value[idx].content || "") + chunk };
    }
  }

  function deleteMessage(msgId: string) {
    const index = messages.value.findIndex(m => m.id === msgId);
    if (index !== -1) {
      messages.value.splice(index, 1);
    }
  }

  function retryMessage(msg: FloatMessage) {
    const msgIndex = messages.value.indexOf(msg);
    let retryContent = "";
    for (let i = msgIndex - 1; i >= 0; i--) {
      if (messages.value[i].role === "user") {
        retryContent = messages.value[i].content;
        break;
      }
    }
    if (!retryContent) return;
    sendMessage(retryContent);
  }

  function sendQuickCommand(command: string) {
    sendMessage(command);
  }

  return {
    isOpen,
    isFullscreen,
    loading,
    messages,
    currentPageId,
    sessionId,
    config,
    configLoaded,
    isVisible,
    fieldHintsCount,
    missingFieldsList,
    agentHealthStatus,
    badgeCount,
    dynamicTitle,
    FORM_PAGE_IDS,
    loadConfig,
    saveConfig,
    setPageId,
    toggleOpen,
    setOpen,
    toggleFullscreen,
    clearMessages,
    sendMessage,
    deleteMessage,
    retryMessage,
    sendQuickCommand,
    showMissingFieldsHint,
    updateFieldHintsLocal,
    fetchFieldHints,
    fetchHealth,
  };
});

import { defineStore } from 'pinia'
import { ref } from 'vue'
import { formulaApi } from '@/api/formula'
import type { Formula, FormulaForm, MaterialItem } from '@/api/formula'
import { formatTimestamp } from '@/utils/timeFormat'
import { MessagePlugin } from 'tdesign-vue-next'

export const useFormulaStore = defineStore('formula', () => {
  const formulas = ref<Formula[]>([])
  const loading = ref(false)
  const total = ref(0)
  const currentPage = ref(1)
  const pageSize = ref(8)
  const keyword = ref('')
  const salesmanId = ref('')

  const fetchFormulas = async () => {
    loading.value = true
    try {
      const res = await formulaApi.getList({
        keyword: keyword.value || undefined,
        salesmanId: salesmanId.value || undefined,
        page: currentPage.value,
        pageSize: pageSize.value,
      })
      // axios 拦截器已经提取了 res.data，所以这里直接使用 res
      // 解析 materialsJson、description 并格式化时间
      formulas.value = res.list.map((f: Formula) => ({
        ...f,
        materials: parseMaterials(f),
        description: parseDescription(f.description),
        createdAt: formatTimestamp(f.createdAt),
        updatedAt: formatTimestamp(f.updatedAt),
      }))
      total.value = res.pagination.total
    } catch (error: any) {
      console.error('获取配方列表失败:', error)
      MessagePlugin.error(error.message || '获取配方数据失败，请检查网络连接')
    } finally {
      loading.value = false
    }
  }

  const getFormula = async (id: string): Promise<Formula | null> => {
    try {
      const res = await formulaApi.getById(id)
      // axios 拦截器已经提取了 res.data，所以这里直接使用 res
      const formula = res
      return {
        ...formula,
        materials: parseMaterials(formula),
        description: parseDescription(formula.description),
        createdAt: formatTimestamp(formula.createdAt),
        updatedAt: formatTimestamp(formula.updatedAt),
      }
    } catch (error: any) {
      console.error('获取配方详情失败:', error)
      MessagePlugin.error(error.message || '获取配方详情失败')
      return null
    }
  }

  const createFormula = async (form: FormulaForm) => {
    loading.value = true
    try {
      const data = await formulaApi.create(form)
      await fetchFormulas()
      return { success: true, data }
    } catch (error: any) {
      return { success: false, message: error.message || '创建失败' }
    } finally {
      loading.value = false
    }
  }

  const updateFormula = async (id: string, form: Partial<FormulaForm>) => {
    loading.value = true
    try {
      await formulaApi.update(id, form)
      await fetchFormulas()
      return { success: true }
    } catch (error: any) {
      return { success: false, message: error.message || '更新失败' }
    } finally {
      loading.value = false
    }
  }

  const deleteFormula = async (id: string) => {
    loading.value = true
    try {
      await formulaApi.delete(id)
      await fetchFormulas()
      return { success: true }
    } catch (error: any) {
      return { success: false, message: error.message || '删除失败' }
    } finally {
      loading.value = false
    }
  }

  const setKeyword = (val: string) => {
    keyword.value = val
    currentPage.value = 1
  }

  const setSalesmanId = (val: string) => {
    salesmanId.value = val
    currentPage.value = 1
  }

  const setPage = (page: number) => {
    currentPage.value = page
  }

  return {
    formulas,
    loading,
    total,
    currentPage,
    pageSize,
    keyword,
    salesmanId,
    fetchFormulas,
    getFormula,
    createFormula,
    updateFormula,
    deleteFormula,
    setKeyword,
    setSalesmanId,
    setPage,
  }
})

/** 解析配方的 materialsJson 字段（防御双重序列化） */
function parseMaterials(formula: Formula): MaterialItem[] {
  if (formula.materials) return formula.materials
  if (!formula.materialsJson) return []

  try {
    const parsed = JSON.parse(formula.materialsJson)
    // 防御双重序列化：解析结果可能是字符串（如 "[[{...}]]"）
    if (typeof parsed === 'string') {
      return JSON.parse(parsed)
    }
    // 确保返回数组
    return Array.isArray(parsed) ? parsed : []
  } catch {
    return []
  }
}

/** 解析 description 字段（可能是 JSON 字符串或纯文本） */
export function parseDescription(raw: string | null | undefined): string {
  if (!raw) return ''
  if (typeof raw !== 'string') return String(raw)
  // 尝试解析 JSON，提取可读摘要
  try {
    const obj = JSON.parse(raw)
    if (typeof obj === 'object' && obj !== null) {
      const parts: string[] = []
      if (obj.productType) parts.push(obj.productType)
      if (obj.dosage) parts.push(obj.dosage)
      if (obj.efficacy) parts.push(obj.efficacy)
      if (obj.totalQuote != null) parts.push(`报价: ¥${obj.totalQuote.toFixed(4)}`)
      return parts.length > 0 ? parts.join(' | ') : raw
    }
    return raw
  } catch {
    return raw
  }
}

